def check_username_availability(username):
    """
    Belirtilen kullanıcı adının kullanılabilirliğini kontrol eder.
    Kullanıcı adlarını küçük harfe duyarlı olmayan bir şekilde kontrol eder.
    """
    taken_usernames = [
        "admin", "root", "mehmet", "ayse", "can", "irem", "deneme", "testuser"
    ]

    return username.lower() not in taken_usernames

if __name__ == "__main__":
    while True:
        user_input = input("Kontrol etmek istediğiniz kullanıcı adını girin (çıkmak için 'q' veya 'quit' yazın): ").strip()

        if user_input.lower() in ("q", "quit"):
            print("Çıkılıyor...")
            break

        if not user_input:
            print("Kullanıcı adı boş olamaz. Lütfen geçerli bir kullanıcı adı girin.")
            continue

        if check_username_availability(user_input):
            print(f"'{user_input}' kullanıcı adı MÜSAİT.")
